// Format the debate data into a clean report
const data = $input.first().json;

const winner = data.winner;
const winnerEmoji = winner === 'user' ? '🏆' : winner === 'ai' ? '🤖' : '🤝';
const winnerLabel = winner === 'user' ? 'YOU WIN' : winner === 'ai' ? 'AI WINS' : 'DRAW';

const userOverall = data.scores?.overall?.userScore ?? 0;
const aiOverall = data.scores?.overall?.aiScore ?? 0;

const emailSubject = `${winnerEmoji} P·A·R·I·T·Y Debate: "${data.topic}" — ${winnerLabel}`;

const emailBody = `
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
P·A·R·I·T·Y DEBATE RESULT
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

${winnerEmoji} RESULT: ${winnerLabel}

📋 PROPOSITION: "${data.topic}"
👤 YOUR SIDE:   ${(data.userSide || '').toUpperCase()}
🤖 AI PERSONA:  ${(data.persona || '').charAt(0).toUpperCase() + (data.persona || '').slice(1)}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
SCORE BREAKDOWN
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

Logic:    You ${data.scores?.logic?.userScore ?? 0} vs AI ${data.scores?.logic?.aiScore ?? 0}
Evidence: You ${data.scores?.evidence?.userScore ?? 0} vs AI ${data.scores?.evidence?.aiScore ?? 0}
Clarity:  You ${data.scores?.clarity?.userScore ?? 0} vs AI ${data.scores?.clarity?.aiScore ?? 0}
Overall:  You ${userOverall} vs AI ${aiOverall}

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
VERDICT
━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━

${data.verdict}

⭐ BEST ARGUMENT:
"${data.bestArgument}"

━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
${data.shareText}

Powered by P·A·R·I·T·Y × n8n × Featherless AI
`;

const discordMessage = [
  `${winnerEmoji} **${winnerLabel}** — \"${data.topic}\"`,
  `> ${data.persona?.charAt(0).toUpperCase() + data.persona?.slice(1)} vs You (${data.userSide?.toUpperCase()})`,
  `> Overall: You **${userOverall}** / AI **${aiOverall}**`,
  ``,
  `*${data.verdict?.slice(0, 200)}...*`,
  ``,
  `⭐ Best argument: *\"${data.bestArgument?.slice(0, 150)}\"*`,
].join('\n');

return [{
  json: {
    ...data,
    emailSubject,
    emailBody,
    discordMessage,
    winnerLabel,
    winnerEmoji,
    userOverall,
    aiOverall,
  }
}];
